@article{Levi_Allouche_Ohayon_Puzanov_2025, title={CyberPal.AI: Empowering LLMs with Expert-Driven Cybersecurity Instructions}, volume={39}, url={https://ojs.aaai.org/index.php/AAAI/article/view/34618}, DOI={10.1609/aaai.v39i23.34618}, abstractNote={Large Language Models (LLMs) have significantly advanced natural language processing (NLP), providing versatile capabilities across various applications. However, their application to complex, domain-specific tasks, such as cyber-security, often faces substantial challenges. In this study, we introduce SecKnowledge and CyberPal.AI to address these challenges and train security-expert LLMs.
SecKnowledge is a domain-knowledge-driven cyber-security instruction dataset, meticulously designed using years of accumulated expert knowledge in the domain through a multi-phase generation process. CyberPal.AI refers to a family of LLMs fine-tuned using SecKnowledge, aimed at building security-specialized LLMs capable of answering and following complex security-related instructions. Additionally, we introduce SecKnowledge-Eval, a comprehensive and diverse cyber-security evaluation benchmark, composed of an extensive set of cyber-security tasks we specifically developed to assess LLMs in the field of cyber-security, along with other publicly available security benchmarks.
Extensive evaluations demonstrate a significant average improvement of up to 24% over the baseline models, underscoring the benefits of our expert-driven instruction dataset generation process.
These findings contribute to the advancement of AI-based cyber-security applications, paving the way for robust security-expert LLMs that can enhance threat-hunting and investigation processes.}, number={23}, journal={Proceedings of the AAAI Conference on Artificial Intelligence}, author={Levi, Matan and Allouche, Yair and Ohayon, Daniel and Puzanov, Anton}, year={2025}, month={Apr.}, pages={24402-24412} }

